import pytest

from discount import apply_discount


def test_no_discount():
    assert apply_discount(100, 0) == 100


def test_half():
    assert apply_discount(100, 50) == 50


def test_negative_raises():
    with pytest.raises(ValueError):
        apply_discount(100, -1)
